normalize_hs4 <- function(x) {
  x <- trimws(as.character(x))
  ok <- !is.na(x) & grepl("^[0-9]+$", x) & nchar(x) < 4
  x[ok] <- sprintf("%04d", as.integer(x[ok]))
  x
}
