bol_val <- data.table(indicator=c("ECI","Diversity","HHI","Primary export share"), reported_value=c(-1.235808,82,0.1243863,0.6267532), recalculated_value=c(bol_cy$eci, bol_cy$diversity, hhi_calc, prim), definition=c("standardized country eigenvector","count of HS4 RCA>=1 products","sum of squared HS4 export shares","share of exports in primary HS sections"), numerator=c(NA, bol_trade[mcp==1,.N], NA, sum(bol_trade[product_section %in% c("Animal products","Vegetable products","Fats and oils","Foodstuffs","Minerals"), export_value])), denominator=c(NA, uniqueN(bol_trade$product_code), sum(bol_trade$export_value), sum(bol_trade$export_value)), source_processed="data/processed/trade_country_product_year.parquet", observations=c("relative within year","HS92 4-digit",paste0("regional median HHI=",round(median(regional$hhi,na.rm=TRUE),3),"; percentile=",round(pct_hhi,3),"; rank=",rank_hhi),"primary sections include agriculture, food, fats/oils, minerals"))
