stat_row <- function(x,nm) { x <- as.numeric(x); data.table(variable=nm,min=min(x,na.rm=TRUE),p10=quantile(x,.10,na.rm=TRUE),p25=quantile(x,.25,na.rm=TRUE),median=median(x,na.rm=TRUE),p75=quantile(x,.75,na.rm=TRUE),p90=quantile(x,.90,na.rm=TRUE),max=max(x,na.rm=TRUE),mean=mean(x,na.rm=TRUE),sd=sd(x,na.rm=TRUE),missing=sum(is.na(x))) }
