pct_rank <- function(x){ out<-rep(NA_real_,length(x)); ok<-is.finite(x); if(sum(ok)==1) out[ok]<-1 else if(sum(ok)>1) out[ok]<-(rank(x[ok],ties.method="average")-1)/(sum(ok)-1); out }
world_hist <- trade[year %in% ((latest_year-5):latest_year), .(world_exports=sum(export_value)), by=.(product_code,year)]; cont <- world_hist[world_exports>0,.(positive_years_last6=.N),by=product_code]; current_bol <- unique(bol_trade[mcp==1,product_code])
rev <- merge(copy(opp), cont, by="product_code", all.x=TRUE); rev[is.na(positive_years_last6),positive_years_last6:=0]; rev[, residual_code:=grepl("not elsewhere|n.e.c|n.e.s|nes|special|miscellaneous|commodities not specified|unclassified", paste(product_name,product_name_short), ignore.case=TRUE)]
