rev[,`:=`(density_pct=pct_rank(density), pci_pct=pct_rank(pci_final), opportunity_gain_pct=pct_rank(opportunity_gain), world_market_pct=pct_rank(log1p(world_market_size)), demand_growth_pct=pct_rank(demand_growth))]
score <- function(dt,w){ cols <- names(w); m<-as.matrix(dt[,..cols]); denom<-rowSums(sweep(!is.na(m),2,w,`*`)); fifelse(denom>0,rowSums(sweep(m,2,w,`*`),na.rm=TRUE)/denom,NA_real_) }
rev[, feasibility_score:=score(.SD,c(density_pct=.50,pci_pct=.15,opportunity_gain_pct=.15,world_market_pct=.10,demand_growth_pct=.10)), .SDcols=c("density_pct","pci_pct","opportunity_gain_pct","world_market_pct","demand_growth_pct")]
