openxlsx::write.xlsx(list(all_candidates=rev, absolute_classification=rev[,.N,by=absolute_classification], relative_classification=rev[,.N,by=relative_category], feasibility_top20=head(rev[eligible==TRUE][order(-feasibility_score)],20), transformation_top20=head(rev[eligible==TRUE][order(-transformation_score)],20), quick_wins=rev[relative_category=="Quick wins"][order(-feasibility_score)], strategic_bets=rev[relative_category=="Strategic bets"][order(-transformation_score)], incremental_extensions=rev[relative_category=="Incremental extensions"][order(-feasibility_score)], long_shots=rev[relative_category=="Transformational long shots"][order(-transformation_score)], sector_summary=sector, methodology=meth), p("outputs/tables/xlsx/bolivia_opportunities_revised.xlsx"), overwrite=TRUE)
